import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.COr20JJv.js";const p=JSON.parse('{"title":"项目列表","description":"","frontmatter":{},"headers":[],"relativePath":"projects.md","filePath":"projects.md"}'),l={name:"projects.md"};function i(n,e,s,h,u,g){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="项目列表" tabindex="-1">项目列表 <a class="header-anchor" href="#项目列表" aria-label="Permalink to &quot;项目列表&quot;">​</a></h1><blockquote><p>编辑日期：2026-03-23</p></blockquote><h2 id="ly-开源项目介绍" tabindex="-1">Ly 开源项目介绍 <a class="header-anchor" href="#ly-开源项目介绍" aria-label="Permalink to &quot;Ly 开源项目介绍&quot;">​</a></h2><p>Ly 是一系列开源项目的集合，旨在为企业和开发者提供高质量、易用的解决方案。目前主要包含以下项目：</p><h2 id="_1-lyedu" tabindex="-1">1. LyEdu <a class="header-anchor" href="#_1-lyedu" aria-label="Permalink to &quot;1. LyEdu&quot;">​</a></h2><h3 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h3><p>LyEdu 是一个企业级教育训练系统，专为企业内部培训和学习管理设计。它提供了完整的课程管理、学习跟踪、考试评估等功能，帮助企业构建高效的内部学习平台。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>课程管理</strong>：支持课程创建、分类、章节管理、视频上传等</li><li><strong>学习跟踪</strong>：实时监控学习进度，生成学习报告</li><li><strong>考试评估</strong>：支持在线考试、自动评分、成绩分析等</li><li><strong>用户管理</strong>：支持用户分组、权限管理、部门管理等</li><li><strong>Feishu 集成</strong>：支持 Feishu 登录和地址簿同步</li><li><strong>多端支持</strong>：PC 端和移动端（基于 uni-app x）</li></ul><h3 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h3><ul><li><strong>前端</strong>：Vue 3、TypeScript、Element Plus、uni-app x</li><li><strong>后端</strong>：Spring Boot 4、Java 17、PostgreSQL、Redis</li><li><strong>部署</strong>：Docker、Docker Compose</li></ul><h3 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h3><ul><li><a href="/projects/lyedu/introduction.html">项目介绍</a></li><li><a href="/projects/lyedu/tech-stack.html">技术栈</a></li><li><a href="/projects/lyedu/quick-start.html">快速开始</a></li><li><a href="https://github.com/quxiangshun/ly-edu" target="_blank" rel="noreferrer">GitHub 仓库</a></li><li><a href="https://gitee.com/quxiangshun/ly-edu" target="_blank" rel="noreferrer">Gitee 仓库</a></li><li><a href="https://gitcode.com/quxiangshun/ly-edu" target="_blank" rel="noreferrer">GitCode 仓库</a></li></ul><h2 id="_2-lygenealogy" tabindex="-1">2. LyGenealogy <a class="header-anchor" href="#_2-lygenealogy" aria-label="Permalink to &quot;2. LyGenealogy&quot;">​</a></h2><h3 id="项目简介-1" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介-1" aria-label="Permalink to &quot;项目简介&quot;">​</a></h3><p>LyGenealogy（屈氏宗谱）是基于 <strong>Node.js</strong> 技术栈的开源族谱数字化平台，包含公共前端（Nuxt 3，H5 适配）、管理后台（Vue 3 + Element Plus）和 REST API（Express + TypeScript），采用 pnpm Monorepo，前后端分离，支持多姓氏扩展。</p><h3 id="核心功能-1" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能-1" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>族谱管理</strong>：多族谱，按地区、年代检索，谱籍与字辈摘要</li><li><strong>世系树</strong>：可视化展示世代传承关系</li><li><strong>成员与亲缘</strong>：成员搜索、字辈查询、亲缘关系递归展示</li><li><strong>文化传承</strong>：百科、新闻、姓氏文化展示与管理</li><li><strong>认证与安全</strong>：JWT 登录、首次修改密码、姓名脱敏等</li></ul><h3 id="技术架构-1" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构-1" aria-label="Permalink to &quot;技术架构&quot;">​</a></h3><ul><li><strong>API</strong>：Express + TypeScript，better-sqlite3，JWT</li><li><strong>公共前端</strong>：Nuxt 3 + Vue 3（SSR/SSG/ISR，PWA）</li><li><strong>管理后台</strong>：Vue 3 + Element Plus（SPA）</li><li><strong>包与部署</strong>：pnpm workspace，build.sh 打包，Caddy + PM2</li></ul><h3 id="相关链接-1" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接-1" aria-label="Permalink to &quot;相关链接&quot;">​</a></h3><ul><li><a href="/projects/lygenealogy/introduction.html">项目介绍</a></li><li><a href="/projects/lygenealogy/tech-stack.html">技术栈</a></li><li><a href="/projects/lygenealogy/quick-start.html">快速开始</a></li><li><a href="http://39.106.39.125:9997/" target="_blank" rel="noreferrer">在线演示</a></li><li><a href="https://github.com/quxiangshun/ly-genealogy" target="_blank" rel="noreferrer">GitHub 仓库</a></li></ul><h2 id="_3-lymom" tabindex="-1">3. LyMom <a class="header-anchor" href="#_3-lymom" aria-label="Permalink to &quot;3. LyMom&quot;">​</a></h2><h3 id="项目简介-2" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介-2" aria-label="Permalink to &quot;项目简介&quot;">​</a></h3><p>LyMom (Ly Manufacturing Operations Management) 是一个开源的制造运营管理系统，专为中小型制造企业设计，提供全面的生产管理、设备监控和数据分析功能。</p><h3 id="核心功能-2" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能-2" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>生产管理</strong>：生产计划与排产、工单管理、物料需求计划、生产过程跟踪、质量控制</li><li><strong>设备管理</strong>：设备状态监控、设备维护计划、故障记录与分析、OEE 计算</li><li><strong>数据分析</strong>：生产报表、设备性能分析、质量数据分析、能耗分析</li><li><strong>系统集成</strong>：MES 系统集成、ERP 系统集成、设备控制系统集成、工业协议支持 (OPC UA/Modbus/TCP)</li></ul><h3 id="技术架构-2" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构-2" aria-label="Permalink to &quot;技术架构&quot;">​</a></h3><ul><li><strong>前端</strong>：Vue 3、TypeScript、Element Plus</li><li><strong>后端</strong>：Spring Boot 4、FastAPI、Python 3、PostgreSQL、Redis</li><li><strong>工业协议</strong>：OPC UA、Modbus TCP、MQTT</li><li><strong>部署</strong>：Docker、Docker Compose</li></ul><h3 id="相关链接-2" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接-2" aria-label="Permalink to &quot;相关链接&quot;">​</a></h3><ul><li><a href="/projects/lymom/introduction.html">项目介绍</a></li><li><a href="/projects/lymom/tech-stack.html">技术栈</a></li><li><a href="/projects/lymom/quick-start.html">快速开始</a></li><li><a href="https://github.com/quxiangshun/ly-factmesh-back" target="_blank" rel="noreferrer">GitHub 仓库</a></li><li><a href="https://gitee.com/quxiangshun/ly-factmesh-back" target="_blank" rel="noreferrer">Gitee 仓库</a></li><li><a href="https://gitcode.com/quxiangshun/ly-factmesh-back" target="_blank" rel="noreferrer">GitCode 仓库</a></li></ul><h2 id="lytools" tabindex="-1">4. LyTools <a class="header-anchor" href="#lytools" aria-label="Permalink to &quot;4. LyTools {#lytools}&quot;">​</a></h2><p>LyTools（栾媛小工具）是基于 <strong>Electron + Vue 3 + Element Plus</strong> 的桌面实用工具集，插件化扩展；三端仓库同步维护。</p><p><strong>完整文档</strong>：<a href="/projects/lytools/introduction.html">LyTools 文档</a></p><p><strong>仓库</strong>：<a href="https://github.com/quxiangshun/ly-tools" target="_blank" rel="noreferrer">GitHub</a> · <a href="https://gitee.com/quxiangshun/ly-tools" target="_blank" rel="noreferrer">Gitee</a> · <a href="https://gitcode.com/quxiangshun/ly-tools" target="_blank" rel="noreferrer">GitCode</a></p><hr><h2 id="netbox" tabindex="-1">5. NetBox <a class="header-anchor" href="#netbox" aria-label="Permalink to &quot;5. NetBox {#netbox}&quot;">​</a></h2><p>NetBox 是一个开源的网络基础设施管理和 IP 地址管理（IPAM）解决方案，专为网络工程师设计。</p><p><strong>文档入口</strong>：<a href="/projects/tech-share/netbox/4.5.1/community/">NetBox 4.5.1 Community</a> · <a href="/projects/tech-share/netbox/customer/">学习笔记</a></p><h2 id="newapi" tabindex="-1">6. NewApi <a class="header-anchor" href="#newapi" aria-label="Permalink to &quot;6. NewApi {#newapi}&quot;">​</a></h2><p><a href="https://github.com/QuantumNous/new-api" target="_blank" rel="noreferrer">New API</a> 是统一 AI 模型网关与资产管理系统，支持 OpenAI/Claude/Gemini 等格式转换与集中式模型管理。</p><p><strong>完整文档</strong>：<a href="/projects/newapi/introduction.html">项目介绍</a> · <a href="/projects/newapi/插件开发.html">插件开发</a> · <a href="/projects/newapi/日志插件.html">日志插件</a> · <a href="/projects/newapi/usage_log与上游合并-源码入侵.html">usage_log 与上游合并（源码入侵）</a> · <a href="/projects/newapi/分组与访问配置.html">分组与访问配置</a> · <a href="/projects/newapi/模型.html">模型</a></p><h2 id="未来规划" tabindex="-1">未来规划 <a class="header-anchor" href="#未来规划" aria-label="Permalink to &quot;未来规划&quot;">​</a></h2><p>Ly 系列项目将持续迭代和扩展，未来计划推出以下项目：</p><ul><li><strong>LyCRM</strong>：客户关系管理系统</li><li><strong>LyERP</strong>：企业资源计划系统</li><li><strong>LyIoT</strong>：物联网平台</li></ul><p>欢迎关注和参与 Ly 系列开源项目的开发和贡献！</p>',46)])])}const d=a(l,[["render",i]]);export{p as __pageData,d as default};
